import React from 'react'

export const Clothes = ({props}) => {
    console.log(props.photos[0])
  return (
    <div>
        <h1>Clothes {props.imrp}</h1>
        <div> 

        {
            props.photos && (
                <div>
                <img  className="rounded-2xl w-full object-cover" alt="img not found" src={'http://localhost:5000/'+props.photos[0]} />
                </div>
            )
        }
        </div>
    </div>
  )
}
